 280 | // Helper: Finds code block ignoring whitespace, tabs, newlines, and quote styles
 281 | function findBlockRobust(originalContent: string, searchBlock: string): { start: number; end: number } | null {
 282 |   if (!searchBlock || !originalContent) return null;
 283 | 
 284 |   const createFingerprint = (str: string) => {
 285 |     let clean = "";
 286 |     const map: number[] = [];
 287 |     for (let i = 0; i < str.length; i++) {
 288 |       if (!/\s/.test(str[i])) {
 289 |         clean += str[i];
 290 |         map.push(i);
 291 |       }
 292 |     }
 293 |     return { clean, map };
 294 |   };
 295 | 
 296 |   const fileFP = createFingerprint(originalContent);
 297 |   const searchFP = createFingerprint(searchBlock);
 298 | 
 299 |   // 1. Strict Structural Match
 300 |   let matchIndex = fileFP.clean.indexOf(searchFP.clean);
 301 | 
 302 |   // 2. Quote-Agnostic Fallback (e.g. " vs ')
 303 |   if (matchIndex === -1) {
 304 |     const normalizeQuotes = (s: string) => s.replace(/['"`]/g, '"');
 305 |     matchIndex = normalizeQuotes(fileFP.clean).indexOf(normalizeQuotes(searchFP.clean));
 306 |   }
 307 | 
 308 |   if (matchIndex === -1) return null;
 309 | 
 310 |   const start = fileFP.map[matchIndex];
 311 |   const end = fileFP.map[matchIndex + searchFP.clean.length - 1] + 1;
 312 |   return { start, end };
 313 | }
