 609 |         // Return raw objects so Client/AI can use line numbers
 610 |         return { 
 611 |             supported: true, 
 612 |             valid: data.result.valid, 
 613 |             errors: data.result.errors || [],
 614 |             warning: null 
 615 |         };
 616 |     }
 617 | 
 618 |     // Handle case where validator processed but failed logic
 619 |     return { supported: true, valid: true, errors: [], warning: data.error || "Validator response invalid" };
