 621 |   } catch (e: any) {
 622 |     console.error("Delegated Validation Error:", e);
 623 |     // If the separate function fails, we fallback to saying 'valid' so we don't block the build
 624 |     return { supported: true, valid: true, errors: [], warning: "Syntax check skipped (Service Unavailable)" };
 625 |   }
 626 | }
