 317 |   
 318 |   // Helper to find line by trimmed content
 319 |   const getLineIndex = (anchor: string) => {
 320 |       const cleanAnchor = anchor.trim();
 321 |       return lines.findIndex(l => l.trim() === cleanAnchor);
 322 |   };
 323 | 
 324 |   try {
 325 |     // --- AI HEALING ---
 326 |     if (op.is_ai_fix) {
 327 |         if (op.ai_strategy === "range_replace" && op.start_line && op.end_line) {
 328 |             lines.splice(op.start_line - 1, (op.end_line - op.start_line) + 1, op.replace_with || op.content || "");
 329 |                         const shortMsg = op.explanation ? (op.explanation.substring(0, 150) + "...") : "AI Fixed";
 330 |             return { newContent: lines.join("\n"), success: true, score: 95, message: `✨ AI: ${shortMsg}` };
 331 |         }
 332 | 
 333 |         if (op.ai_strategy === "line_insert" && op.anchor_line) {
 334 |             const idx = op.anchor_line - 1;
 335 |             const payload = op.replace_with || op.content || "";
 336 |             if (op.action === "insert_after") {
 337 |                 lines.splice(idx + 1, 0, payload);
 338 |             } else if (op.action === "insert_before") {
 339 |                 lines.splice(idx, 0, payload);
 340 |             } else {
 341 |                 lines[idx] = payload;
 342 |             }
 343 |             const shortMsg = op.explanation ? (op.explanation.substring(0, 150) + "...") : "AI Fixed";
 344 |             return { newContent: lines.join("\n"), success: true, score: 95, message: `Ã¢ÂÂ¨ AI: ${shortMsg}` };
 345 |         }
 346 |     }
 347 | 
 348 |     switch (op.action) {
 349 |       case "replace_block": {
 350 |         if (!op.find_block) return { newContent: content, success: false, score: 0, message: "Missing find_block" };
 351 |         
 352 |         // Strategy A: Exact Match
 353 |         if (content.includes(op.find_block)) {
 354 |             return { newContent: content.replace(op.find_block, op.replace_with || ""), success: true, score: 100, message: "Exact match" };
 355 |         }
 356 |         // Strategy B: Robust Match (Ignores whitespace/indentation)
 357 |         const match = findBlockRobust(content, op.find_block);
 358 |         if (match) {
 359 |             const before = content.substring(0, match.start);
 360 |             const after = content.substring(match.end);
 361 |             return { newContent: before + (op.replace_with || "") + after, success: true, score: 95, message: "Structure match" };
 362 |         }
 363 |         return { newContent: content, success: false, score: 0, message: "Block not found" };
 364 |       }
 365 | 
 366 |       case "insert_after": {
 367 |         // Strategy A: Exact Line
 368 |         let idx = lines.indexOf(op.anchor);
 369 |         // Strategy B: Trimmed Line
 370 |         if (idx === -1) idx = getLineIndex(op.anchor);
 371 |         
 372 |         if (idx !== -1) {
 373 |             lines.splice(idx + 1, 0, op.content);
 374 |             return { newContent: lines.join("\n"), success: true, score: 100, message: "Inserted after line" };
 375 |         }
 376 |         
 377 |         // Strategy C: Robust Block Anchor
 378 |         const match = findBlockRobust(content, op.anchor);
 379 |         if (match) {
 380 |              const before = content.substring(0, match.end);
 381 |              const after = content.substring(match.end);
 382 |              return { newContent: before + "\n" + op.content + after, success: true, score: 90, message: "Robust anchor match" };
 383 |         }
 384 |         return { newContent: content, success: false, score: 0, message: "Anchor not found" };
 385 |       }
 386 | 
 387 |       case "insert_before": {
 388 |         let idx = lines.indexOf(op.anchor);
 389 |         if (idx === -1) idx = getLineIndex(op.anchor);
 390 | 
 391 |         if (idx !== -1) {
 392 |             lines.splice(idx, 0, op.content);
 393 |             return { newContent: lines.join("\n"), success: true, score: 100, message: "Inserted before line" };
 394 |         }
 395 | 
 396 |         const match = findBlockRobust(content, op.anchor);
 397 |         if (match) {
 398 |              const before = content.substring(0, match.start);
 399 |              const after = content.substring(match.start);
 400 |              return { newContent: before + op.content + "\n" + after, success: true, score: 90, message: "Robust anchor match" };
 401 |         }
 402 |         return { newContent: content, success: false, score: 0, message: "Anchor not found" };
 403 |       }
 404 | 
 405 |       case "replace_between_anchors":
 406 |         const s = content.indexOf(op.start_anchor), e = content.indexOf(op.end_anchor);
 407 |         if(s > -1 && e > -1 && e > s) {
 408 |              const pre = content.substring(0, s + op.start_anchor.length), post = content.substring(e);
 409 |              return { newContent: pre + "\n" + op.content + "\n" + post, success: true, score: 100, message: "Range replaced" };
 410 |         }
 411 |         return { newContent: content, success: false, score: 0, message: "Anchors not found" };
 412 | 
 413 |       case "create_file": 
 414 |         return { newContent: op.content || "", success: true, score: 100, message: "Created" };
 415 | 
 416 |       case "delete_file":
 417 |          return { newContent: "", success: true, score: 100, message: "Deleted" };
 418 | 
 419 |       default: 
 420 |         return { newContent: content, success: false, score: 0, message: "Unknown action" };
 421 |     }
 422 |   } catch(e:any) { 
 423 |       return { newContent: content, success: false, score: 0, message: `Err: ${e.message}` }; 
 424 |   }
 425 | }
