 315 | function applyOperation(content: string, op: any) {
 316 |   const lines = content.split("\n");
 317 |   
 318 |   // Helper to find line by trimmed content
 319 |   const getLineIndex = (anchor: string) => {
 320 |       const cleanAnchor = anchor.trim();
 321 |       return lines.findIndex(l => l.trim() === cleanAnchor);
 322 |   };
 323 | 
 324 |   try {
 325 |     // --- AI HEALING ---
 326 |     if (op.is_ai_fix) {
 327 |         if (op.ai_strategy === "range_replace" && op.start_line && op.end_line) {
 328 |             lines.splice(op.start_line - 1, (op.end_line - op.start_line) + 1, op.replace_with || op.content || "");
 329 |                         const shortMsg = op.explanation ? (op.explanation.substring(0, 150) + "...") : "AI Fixed";
 330 |             return { newContent: lines.join("\n"), success: true, score: 95, message: `✨ AI: ${shortMsg}` };
 331 |         }
 332 | 
 333 |         if (op.ai_strategy === "line_insert" && op.anchor_line) {
 334 |             const shortMsg = op.explanation ? (op.explanation.substring(0, 150) + "...") : "AI Fixed";
 335 |             return { newContent: lines.join("\n"), success: true, score: 95, message: `✨ AI: ${shortMsg}` };
 336 |             const payload = op.replace_with || op.content || "";
 337 |             if (op.action === "insert_after") {
 338 |                 lines.splice(idx + 1, 0, payload);
 339 |             } else if (op.action === "insert_before") {
 340 |                 lines.splice(idx, 0, payload);
 341 |             } else {
 342 |                 lines[idx] = payload;
 343 |             }
 344 |             const shortMsg = op.explanation ? (op.explanation.substring(0, 150) + "...") : "AI Fixed";
 345 |             return { newContent: lines.join("\n"), success: true, score: 95, message: `Ã¢ÂÂ¨ AI: ${shortMsg}` };
 346 |         }
 347 |     }
 348 | 
 349 |     switch (op.action) {
 350 |       case "replace_block": {
 351 |         if (!op.find_block) return { newContent: content, success: false, score: 0, message: "Missing find_block" };
 352 |         
 353 |         // Strategy A: Exact Match
 354 |         if (content.includes(op.find_block)) {
 355 |             return { newContent: content.replace(op.find_block, op.replace_with || ""), success: true, score: 100, message: "Exact match" };
 356 |         }
 357 |         // Strategy B: Robust Match (Ignores whitespace/indentation)
 358 |         const match = findBlockRobust(content, op.find_block);
 359 |         if (match) {
 360 |             const before = content.substring(0, match.start);
 361 |             const after = content.substring(match.end);
 362 |             return { newContent: before + (op.replace_with || "") + after, success: true, score: 95, message: "Structure match" };
 363 |         }
 364 |         return { newContent: content, success: false, score: 0, message: "Block not found" };
 365 |       }
 366 | 
 367 |       case "insert_after": {
 368 |         // Strategy A: Exact Line
 369 |         let idx = lines.indexOf(op.anchor);
 370 |         // Strategy B: Trimmed Line
 371 |         if (idx === -1) idx = getLineIndex(op.anchor);
 372 |         
 373 |         if (idx !== -1) {
 374 |             lines.splice(idx + 1, 0, op.content);
 375 |             return { newContent: lines.join("\n"), success: true, score: 100, message: "Inserted after line" };
 376 |         }
 377 |         
 378 |         // Strategy C: Robust Block Anchor
 379 |         const match = findBlockRobust(content, op.anchor);
 380 |         if (match) {
 381 |              const before = content.substring(0, match.end);
 382 |              const after = content.substring(match.end);
 383 |              return { newContent: before + "\n" + op.content + after, success: true, score: 90, message: "Robust anchor match" };
 384 |         }
 385 |         return { newContent: content, success: false, score: 0, message: "Anchor not found" };
 386 |       }
 387 | 
 388 |       case "insert_before": {
 389 |         let idx = lines.indexOf(op.anchor);
 390 |         if (idx === -1) idx = getLineIndex(op.anchor);
 391 | 
 392 |         if (idx !== -1) {
 393 |             lines.splice(idx, 0, op.content);
 394 |             return { newContent: lines.join("\n"), success: true, score: 100, message: "Inserted before line" };
 395 |         }
 396 | 
 397 |         const match = findBlockRobust(content, op.anchor);
 398 |         if (match) {
 399 |              const before = content.substring(0, match.start);
 400 |              const after = content.substring(match.start);
 401 |              return { newContent: before + op.content + "\n" + after, success: true, score: 90, message: "Robust anchor match" };
 402 |         }
 403 |         return { newContent: content, success: false, score: 0, message: "Anchor not found" };
 404 |       }
 405 | 
 406 |       case "replace_between_anchors":
 407 |         const s = content.indexOf(op.start_anchor), e = content.indexOf(op.end_anchor);
 408 |         if(s > -1 && e > -1 && e > s) {
 409 |              const pre = content.substring(0, s + op.start_anchor.length), post = content.substring(e);
 410 |              return { newContent: pre + "\n" + op.content + "\n" + post, success: true, score: 100, message: "Range replaced" };
 411 |         }
 412 |         return { newContent: content, success: false, score: 0, message: "Anchors not found" };
 413 | 
 414 |       case "create_file": 
 415 |         return { newContent: op.content || "", success: true, score: 100, message: "Created" };
 416 | 
 417 |       case "delete_file":
 418 |          return { newContent: "", success: true, score: 100, message: "Deleted" };
 419 | 
 420 |       default: 
 421 |         return { newContent: content, success: false, score: 0, message: "Unknown action" };
 422 |     }
 423 |   } catch(e:any) { 
 424 |       return { newContent: content, success: false, score: 0, message: `Err: ${e.message}` }; 
 425 |   }
 426 | }
