 429 | async function processOperations(TARGET_REPO: string, operations: any[], projectPath: string, autoSanity: boolean, config?: AIConfig) {
 430 |     const scopePath = projectPath || "";
 431 |     if (scopePath) {
 432 |         const invalidOps = operations.filter((op: any) => {
 433 |             if (!op.file_path) return false;
 434 |             // Security Exception: Allow if inside scope OR is an Edge Function deployment
 435 |             const isScoped = op.file_path.startsWith(scopePath);
 436 |             const isEf = op.is_resolved_ef === true || op.file_path.startsWith("supabase/functions/");
 437 |             return !isScoped && !isEf;
 438 |         });
 439 |         if (invalidOps.length > 0) throw new Error(`Security: Operation on ${invalidOps[0].file_path} is outside project scope '${scopePath}'`);
 440 |     }
 441 |     
 442 |     let actualOps = [...operations];
 443 |     let patchNote = "";
 444 |     if (operations[0]?.action === 'comment') {
 445 |         patchNote = operations[0].text || "";
 446 |         actualOps = operations.slice(1);
 447 |     }
 448 |     const patchTitle = patchNote ? patchNote.split('\n')[0].substring(0, 60) : `Patch: ${actualOps.length} operations`;
 449 |     
 450 |     const devBranchRef = await githubFetch(TARGET_REPO, `/git/ref/heads/${DEV_BRANCH}`);
 451 |     const shaBeforePatch = devBranchRef.object.sha;
 452 | 
 453 |     const fileResults: any[] = [];
 454 |     const opsByFile: Record<string, any[]> = {};
 455 |     actualOps.forEach((op: any) => { if (op.file_path) { if (!opsByFile[op.file_path]) opsByFile[op.file_path] = []; opsByFile[op.file_path].push(op); } });
 456 | 
 457 |     let lastCommitSha = "";
 458 |     let anyOpFailed = false;
 459 | 
 460 |     for (const filePath of Object.keys(opsByFile)) {
 461 |         const opLogs: any[] = [];
 462 |         const fileOps = opsByFile[filePath];
 463 |         let { content, sha } = await getFileRaw(TARGET_REPO, filePath, DEV_BRANCH);
 464 | 
 465 |         // --- 1. EXPLICIT FILE EXISTENCE CHECK ---
 466 |         // If file has no SHA (doesn't exist) and we aren't running a 'create_file' op, fail early.
 467 |         const isCreation = fileOps.some((op: any) => op.action === "create_file");
 468 |         if (!sha && !isCreation) {
 469 |             anyOpFailed = true;
 470 |             fileOps.forEach((op: any) => {
 471 |                 opLogs.push({ 
 472 |                     type: op.action, 
 473 |                     success: false, 
 474 |                     score: 0, 
 475 |                     message: `File path not found: ${filePath}` 
 476 |                 });
 477 |             });
 478 |             fileResults.push({ file: filePath, status: "error", operations: opLogs });
 479 |             continue; // Skip to next file
 480 |         }
 481 | 
 482 |         let currentContent = base64ToText(content);
 483 |         let anyChange = false;
 484 | 
 485 |         for (const op of fileOps) {
 486 |             if (op.action === "delete_file") {
 487 |                 if (!sha) { opLogs.push({ type: "delete_file", success: true, score: 100, message: "File already gone" }); }
 488 |                 else {
 489 |                     try {
 490 |                         lastCommitSha = await deleteFile(TARGET_REPO, filePath, sha, DEV_BRANCH, `Conduit: Delete ${filePath}`);
 491 |                         opLogs.push({ type: "delete_file", success: true, score: 100, message: "Deleted" });
 492 |                     } catch (e: any) { opLogs.push({ type: "delete_file", success: false, score: 0, message: e.message }); anyOpFailed = true; }
 493 |                 }
 494 |                 currentContent = ""; sha = ""; continue;
 495 |             }
 496 | 
 497 |             let result = (op.action === "create_file") ? applyOperation("", op) : applyOperation(currentContent, op);
 498 | 
 499 |             if (!result.success && op.action !== "create_file") {
 500 |                 // --- 2. ENHANCED AI HEALER ---
 501 |                 const { fixedOp, reason, score } = await consultAI(currentContent, op, result.message, config);
 502 |                 
 503 |                 if (fixedOp) {
 504 |                     fixedOp.explanation = reason; 
 505 |                     let retryResult = applyOperation(currentContent, fixedOp);
 506 |                     
 507 |                     // Sanity Check Logic
 508 |                     if (retryResult.success && autoSanity) {
 509 |                          const sanity = await checkCodeSanity(retryResult.newContent, fixedOp, config);
 510 |                          if (!sanity.sane) {
 511 |                              opLogs.push({ type: "sanity_check", success: false, message: `Sanity Failed: ${sanity.issues}` });
 512 |                              // Recursively fix sanity
 513 |                              const { fixedOp: sanityOp, reason: sanityReason } = await consultAI(currentContent, fixedOp, `The operation ${JSON.stringify(fixedOp)} caused this syntax error: ${sanity.issues}`, config);
 514 |                              if (sanityOp) {
 515 |                                  const sanityResult = applyOperation(currentContent, sanityOp);
 516 |                                  if (sanityResult.success) { retryResult = sanityResult; fixedOp.explanation = `Auto-corrected sanity issue: ${sanityReason}`; }
 517 |                              }
 518 |                          }
 519 |                     }
 520 | 
 521 |                     if (retryResult.success) {
 522 |                         currentContent = retryResult.newContent;
 523 |                         anyChange = true;
 524 |                         opLogs.push({ type: op.action, success: true, score: score, message: retryResult.message, ...fixedOp });
 525 |                         continue; 
 526 |                     } else {
 527 |                         anyOpFailed = true;
 528 |                         opLogs.push({ type: op.action, success: false, score: 0, message: `AI Fix Failed: ${retryResult.message}` });
 529 |                     }
 530 |                 } else {
 531 |                     // --- 3. DETAILED FAILURE LOGGING ---
 532 |                     anyOpFailed = true;
 533 |                     const failMsg = score > 0 
 534 |                         ? `Block not found. (Best Match: ${score}%). AI Reason: ${reason}`
 535 |                         : `Block not found. AI could not locate target. (${reason})`;
 536 |                         
 537 |                     opLogs.push({ type: op.action, success: false, score: score, message: failMsg });
 538 |                 }
 539 |             } else {
 540 |                 if (result.success) { currentContent = result.newContent; anyChange = true; } else { anyOpFailed = true; }
 541 |                 opLogs.push({ type: op.action, success: result.success, score: result.score, message: result.message, ...op });
 542 |             }
 543 |         }
 544 | 
 545 |         if (anyChange) {
 546 |             try { lastCommitSha = await updateFile(TARGET_REPO, filePath, currentContent, sha, DEV_BRANCH, patchTitle); } 
 547 |             catch (e: any) { anyOpFailed = true; opLogs.push({ type: 'commit_file', success: false, message: `Commit failed: ${e.message}` }); }
 548 |         }
 549 |         fileResults.push({ file: filePath, status: anyChange ? "updated" : "unchanged", operations: opLogs });
 550 |     }
 551 | 
 552 |     if (anyOpFailed && lastCommitSha) {
 553 |         await githubFetch(TARGET_REPO, `/git/refs/heads/${DEV_BRANCH}`, { method: "PATCH", body: JSON.stringify({ sha: shaBeforePatch, force: true }) });
 554 |         const logData = { success: false, commit_sha: null, rollback_to: shaBeforePatch, message: "Patch failed, rolled back.", results: fileResults, ops: operations };
 555 |         await supabase.from('conduit_logs').insert({ repo_name: TARGET_REPO, type: 'patch_failed', data: logData });
 556 |         return logData;
 557 |     }
 558 | 
 559 |     const success = !anyOpFailed;
 560 |     const finalCommitSha = success ? lastCommitSha : null;
 561 |     const logData = { success, commit_sha: finalCommitSha, sha_before: shaBeforePatch, results: fileResults, ops: operations };
 562 | 
 563 |     if (success && lastCommitSha) {
 564 |         const { data: newHistory, error } = await supabase.from('conduit_history')
 565 |             .insert({ repo_name: TARGET_REPO, title: patchTitle, note: patchNote, type: "Dev", meta: `${actualOps.length} ops`, ops: operations, sha: lastCommitSha })
 566 |             .select('conduit_id')
 567 |             .single();
 568 | 
 569 |         if (newHistory) {
 570 |             logData.conduit_id = newHistory.conduit_id; // Add the new ID to the response
 571 |         }
 572 |         logData.sha = lastCommitSha; // Add SHA to the log data for linking
 573 |     }
 574 |     await supabase.from('conduit_logs').insert({ repo_name: TARGET_REPO, type: 'patch', data: logData });
 575 |     return logData;
 576 | }
