 441 |     let actualOps = [...operations];
 442 |     let patchNote = "";
 443 |     if (operations[0]?.action === 'comment') {
 444 |         patchNote = operations[0].text || "";
 445 |         actualOps = operations.slice(1);
 446 |     }
