 448 |     
 449 |     const devBranchRef = await githubFetch(TARGET_REPO, `/git/ref/heads/${DEV_BRANCH}`);
 450 |     const shaBeforePatch = devBranchRef.object.sha;
 451 | 
 452 |     const fileResults: any[] = [];
 453 |     const opsByFile: Record<string, any[]> = {};
 454 |     actualOps.forEach((op: any) => { if (op.file_path) { if (!opsByFile[op.file_path]) opsByFile[op.file_path] = []; opsByFile[op.file_path].push(op); } });
 455 | 
 456 |     let lastCommitSha = "";
 457 |     let anyOpFailed = false;
 458 | 
 459 |     for (const filePath of Object.keys(opsByFile)) {
 460 |         const opLogs: any[] = [];
 461 |         const fileOps = opsByFile[filePath];
 462 |         let { content, sha } = await getFileRaw(TARGET_REPO, filePath, DEV_BRANCH);
 463 | 
 464 |         // --- 1. EXPLICIT FILE EXISTENCE CHECK ---
 465 |         // If file has no SHA (doesn't exist) and we aren't running a 'create_file' op, fail early.
 466 |         const isCreation = fileOps.some((op: any) => op.action === "create_file");
 467 |         if (!sha && !isCreation) {
 468 |             anyOpFailed = true;
 469 |             fileOps.forEach((op: any) => {
 470 |                 opLogs.push({ 
 471 |                     type: op.action, 
 472 |                     success: false, 
 473 |                     score: 0, 
 474 |                     message: `File path not found: ${filePath}` 
 475 |                 });
 476 |             });
 477 |             fileResults.push({ file: filePath, status: "error", operations: opLogs });
 478 |             continue; // Skip to next file
 479 |         }
 480 | 
 481 |         let currentContent = base64ToText(content);
 482 |         let anyChange = false;
 483 | 
 484 |         for (const op of fileOps) {
 485 |             if (op.action === "delete_file") {
 486 |                 if (!sha) { opLogs.push({ type: "delete_file", success: true, score: 100, message: "File already gone" }); }
 487 |                 else {
 488 |                     try {
 489 |                         lastCommitSha = await deleteFile(TARGET_REPO, filePath, sha, DEV_BRANCH, `Conduit: Delete ${filePath}`);
 490 |                         opLogs.push({ type: "delete_file", success: true, score: 100, message: "Deleted" });
 491 |                     } catch (e: any) { opLogs.push({ type: "delete_file", success: false, score: 0, message: e.message }); anyOpFailed = true; }
 492 |                 }
 493 |                 currentContent = ""; sha = ""; continue;
 494 |             }
 495 | 
 496 |             let result = (op.action === "create_file") ? applyOperation("", op) : applyOperation(currentContent, op);
 497 | 
 498 |             if (!result.success && op.action !== "create_file") {
 499 |                 // --- 2. ENHANCED AI HEALER ---
 500 |                 const { fixedOp, reason, score } = await consultAI(currentContent, op, result.message, config);
 501 |                 
 502 |                 if (fixedOp) {
 503 |                     fixedOp.explanation = reason; 
 504 |                     let retryResult = applyOperation(currentContent, fixedOp);
 505 |                     
 506 |                     // Sanity Check Logic
 507 |                     if (retryResult.success && autoSanity) {
 508 |                          const sanity = await checkCodeSanity(retryResult.newContent, fixedOp, config);
 509 |                          if (!sanity.sane) {
 510 |                              opLogs.push({ type: "sanity_check", success: false, message: `Sanity Failed: ${sanity.issues}` });
 511 |                              // Recursively fix sanity
 512 |                              const { fixedOp: sanityOp, reason: sanityReason } = await consultAI(currentContent, fixedOp, `The operation ${JSON.stringify(fixedOp)} caused this syntax error: ${sanity.issues}`, config);
 513 |                              if (sanityOp) {
 514 |                                  const sanityResult = applyOperation(currentContent, sanityOp);
 515 |                                  if (sanityResult.success) { retryResult = sanityResult; fixedOp.explanation = `Auto-corrected sanity issue: ${sanityReason}`; }
 516 |                              }
 517 |                          }
 518 |                     }
 519 | 
 520 |                     if (retryResult.success) {
 521 |                         currentContent = retryResult.newContent;
 522 |                         anyChange = true;
 523 |                         opLogs.push({ type: op.action, success: true, score: score, message: retryResult.message, ...fixedOp });
 524 |                         continue; 
 525 |                     } else {
 526 |                         anyOpFailed = true;
 527 |                         opLogs.push({ type: op.action, success: false, score: 0, message: `AI Fix Failed: ${retryResult.message}` });
 528 |                     }
 529 |                 } else {
 530 |                     // --- 3. DETAILED FAILURE LOGGING ---
 531 |                     anyOpFailed = true;
 532 |                     const failMsg = score > 0 
 533 |                         ? `Block not found. (Best Match: ${score}%). AI Reason: ${reason}`
 534 |                         : `Block not found. AI could not locate target. (${reason})`;
 535 |                         
 536 |                     opLogs.push({ type: op.action, success: false, score: score, message: failMsg });
 537 |                 }
 538 |             } else {
 539 |                 if (result.success) { currentContent = result.newContent; anyChange = true; } else { anyOpFailed = true; }
 540 |                 opLogs.push({ type: op.action, success: result.success, score: result.score, message: result.message, ...op });
 541 |             }
 542 |         }
 543 | 
 544 |         if (anyChange) {
 545 |             try { lastCommitSha = await updateFile(TARGET_REPO, filePath, currentContent, sha, DEV_BRANCH, patchTitle); } 
 546 |             catch (e: any) { anyOpFailed = true; opLogs.push({ type: 'commit_file', success: false, message: `Commit failed: ${e.message}` }); }
 547 |         }
 548 |         fileResults.push({ file: filePath, status: anyChange ? "updated" : "unchanged", operations: opLogs });
 549 |     }
 550 | 
 551 |     if (anyOpFailed && lastCommitSha) {
 552 |         await githubFetch(TARGET_REPO, `/git/refs/heads/${DEV_BRANCH}`, { method: "PATCH", body: JSON.stringify({ sha: shaBeforePatch, force: true }) });
 553 |         const logData = { success: false, commit_sha: null, rollback_to: shaBeforePatch, message: "Patch failed, rolled back.", results: fileResults, ops: operations };
 554 |         await supabase.from('conduit_logs').insert({ repo_name: TARGET_REPO, type: 'patch_failed', data: logData });
 555 |         return logData;
 556 |     }
 557 | 
 558 |     const success = !anyOpFailed;
 559 |     const finalCommitSha = success ? lastCommitSha : null;
 560 |     const logData = { success, commit_sha: finalCommitSha, sha_before: shaBeforePatch, results: fileResults, ops: operations };
 561 | 
 562 |     if (success && lastCommitSha) {
 563 |         const { data: newHistory, error } = await supabase.from('conduit_history')
 564 |             .insert({ repo_name: TARGET_REPO, title: patchTitle, note: patchNote, type: "Dev", meta: `${actualOps.length} ops`, ops: operations, sha: lastCommitSha })
 565 |             .select('conduit_id')
 566 |             .single();
 567 | 
 568 |         if (newHistory) {
 569 |             logData.conduit_id = newHistory.conduit_id; // Add the new ID to the response
 570 |         }
 571 |         logData.sha = lastCommitSha; // Add SHA to the log data for linking
 572 |     }
 573 |     await supabase.from('conduit_logs').insert({ repo_name: TARGET_REPO, type: 'patch', data: logData });
 574 |     return logData;
 575 | }
