 279 | // Helper: Finds code block ignoring whitespace, tabs, newlines, and quote styles
 280 | function findBlockRobust(originalContent: string, searchBlock: string): { start: number; end: number } | null {
 281 |   if (!searchBlock || !originalContent) return null;
 282 | 
 283 |   const createFingerprint = (str: string) => {
 284 |     let clean = "";
 285 |     const map: number[] = [];
 286 |     for (let i = 0; i < str.length; i++) {
 287 |       if (!/\s/.test(str[i])) {
 288 |         clean += str[i];
 289 |         map.push(i);
 290 |       }
 291 |     }
 292 |     return { clean, map };
 293 |   };
 294 | 
 295 |   const fileFP = createFingerprint(originalContent);
 296 |   const searchFP = createFingerprint(searchBlock);
 297 | 
 298 |   // 1. Strict Structural Match
 299 |   let matchIndex = fileFP.clean.indexOf(searchFP.clean);
 300 | 
 301 |   // 2. Quote-Agnostic Fallback (e.g. " vs ')
 302 |   if (matchIndex === -1) {
 303 |     const normalizeQuotes = (s: string) => s.replace(/['"`]/g, '"');
 304 |     matchIndex = normalizeQuotes(fileFP.clean).indexOf(normalizeQuotes(searchFP.clean));
 305 |   }
 306 | 
 307 |   if (matchIndex === -1) return null;
 308 | 
 309 |   const start = fileFP.map[matchIndex];
 310 |   const end = fileFP.map[matchIndex + searchFP.clean.length - 1] + 1;
 311 |   return { start, end };
 312 | }
