 451 |     const shaBeforePatch = devBranchRef.object.sha;
 452 | 
 453 |     const fileResults: any[] = [];
 454 |     const opsByFile: Record<string, any[]> = {};
 455 |     actualOps.forEach((op: any) => { if (op.file_path) { if (!opsByFile[op.file_path]) opsByFile[op.file_path] = []; opsByFile[op.file_path].push(op); } });
 456 | 
 457 |     let lastCommitSha = "";
 458 |     let anyOpFailed = false;
 459 | 
 460 |     for (const filePath of Object.keys(opsByFile)) {
 461 |         const opLogs: any[] = [];
 462 |         const fileOps = opsByFile[filePath];
 463 |         let { content, sha } = await getFileRaw(TARGET_REPO, filePath, DEV_BRANCH);
 464 | 
 465 |         // --- 1. EXPLICIT FILE EXISTENCE CHECK ---
 466 |         // If file has no SHA (doesn't exist) and we aren't running a 'create_file' op, fail early.
 467 |         const isCreation = fileOps.some((op: any) => op.action === "create_file");
 468 |         if (!sha && !isCreation) {
 469 |             anyOpFailed = true;
 470 |             fileOps.forEach((op: any) => {
 471 |                 opLogs.push({ 
 472 |                     type: op.action, 
 473 |                     success: false, 
 474 |                     score: 0, 
 475 |                     message: `File path not found: ${filePath}` 
 476 |                 });
 477 |             });
 478 |             fileResults.push({ file: filePath, status: "error", operations: opLogs });
 479 |             continue; // Skip to next file
 480 |         }
 481 | 
 482 |         let currentContent = base64ToText(content);
 483 |         let anyChange = false;
 484 | 
 485 |         for (const op of fileOps) {
 486 |             if (op.action === "delete_file") {
 487 |                 if (!sha) { opLogs.push({ type: "delete_file", success: true, score: 100, message: "File already gone" }); }
 488 |                 else {
 489 |                     try {
 490 |                         lastCommitSha = await deleteFile(TARGET_REPO, filePath, sha, DEV_BRANCH, `Conduit: Delete ${filePath}`);
 491 |                         opLogs.push({ type: "delete_file", success: true, score: 100, message: "Deleted" });
 492 |                     } catch (e: any) { opLogs.push({ type: "delete_file", success: false, score: 0, message: e.message }); anyOpFailed = true; }
 493 |                 }
 494 |                 currentContent = ""; sha = ""; continue;
 495 |             }
 496 | 
 497 |             let result = (op.action === "create_file") ? applyOperation("", op) : applyOperation(currentContent, op);
 498 | 
 499 |             if (!result.success && op.action !== "create_file") {
 500 |                 // --- 2. ENHANCED AI HEALER ---
 501 |                 const { fixedOp, reason, score } = await consultAI(currentContent, op, result.message, config);
 502 |                 
 503 |                 if (fixedOp) {
