 511 |                              opLogs.push({ type: "sanity_check", success: false, message: `Sanity Failed: ${sanity.issues}` });
 512 |                              // Recursively fix sanity
 513 |                              const { fixedOp: sanityOp, reason: sanityReason } = await consultAI(currentContent, fixedOp, `The operation ${JSON.stringify(fixedOp)} caused this syntax error: ${sanity.issues}`, config);
 514 |                              if (sanityOp) {
