 523 |                         anyChange = true;
 524 |                         opLogs.push({ type: op.action, success: true, score: score, message: retryResult.message, ...fixedOp });
 525 |                         continue; 
 526 |                     } else {
 527 |                         anyOpFailed = true;
 528 |                         opLogs.push({ type: op.action, success: false, score: 0, message: `AI Fix Failed: ${retryResult.message}` });
 529 |                     }
