 536 |                         
 537 |                     opLogs.push({ type: op.action, success: false, score: score, message: failMsg });
 538 |                 }
 539 |             } else {
 540 |                 if (result.success) { currentContent = result.newContent; anyChange = true; } else { anyOpFailed = true; }
 541 |                 opLogs.push({ type: op.action, success: result.success, score: result.score, message: result.message, ...op });
 542 |             }
