 278 | // Helper: Finds code block ignoring whitespace, tabs, newlines, and quote styles
 279 | function findBlockRobust(originalContent: string, searchBlock: string): { start: number; end: number } | null {
 280 |   if (!searchBlock || !originalContent) return null;
 281 | 
 282 |   const createFingerprint = (str: string) => {
 283 |     let clean = "";
 284 |     const map: number[] = [];
 285 |     for (let i = 0; i < str.length; i++) {
 286 |       if (!/\s/.test(str[i])) {
 287 |         clean += str[i];
 288 |         map.push(i);
 289 |       }
 290 |     }
 291 |     return { clean, map };
 292 |   };
 293 | 
 294 |   const fileFP = createFingerprint(originalContent);
 295 |   const searchFP = createFingerprint(searchBlock);
 296 | 
 297 |   // 1. Strict Structural Match
 298 |   let matchIndex = fileFP.clean.indexOf(searchFP.clean);
 299 | 
 300 |   // 2. Quote-Agnostic Fallback (e.g. " vs ')
 301 |   if (matchIndex === -1) {
 302 |     const normalizeQuotes = (s: string) => s.replace(/['"`]/g, '"');
 303 |     matchIndex = normalizeQuotes(fileFP.clean).indexOf(normalizeQuotes(searchFP.clean));
 304 |   }
 305 | 
 306 |   if (matchIndex === -1) return null;
 307 | 
 308 |   const start = fileFP.map[matchIndex];
 309 |   const end = fileFP.map[matchIndex + searchFP.clean.length - 1] + 1;
 310 |   return { start, end };
 311 | }
